import sys
import itertools
import math
from collections import defaultdict

MOD = 998244353

def main():
    sys.setrecursionlimit(1 << 25)
    H, W = map(int, sys.stdin.readline().split())
    grid = [list(sys.stdin.readline().strip()) for _ in range(H)]

    # Directions: up, down, left, right
    dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    # DSU implementation
    class DSU:
        def __init__(self, size):
            self.parent = list(range(size))
            self.rank = [0] * size
            self.size = size

        def find(self, x):
            if self.parent[x] != x:
                self.parent[x] = self.find(self.parent[x])
            return self.parent[x]

        def union(self, x, y):
            x_root = self.find(x)
            y_root = self.find(y)
            if x_root == y_root:
                return False
            if self.rank[x_root] < self.rank[y_root]:
                self.parent[x_root] = y_root
            else:
                self.parent[y_root] = x_root
                if self.rank[x_root] == self.rank[y_root]:
                    self.rank[x_root] += 1
            return True

    # Map each green cell to a unique index
    green_cells = []
    for i in range(H):
        for j in range(W):
            if grid[i][j] == '#':
                green_cells.append((i, j))

    # Map (i,j) to index
    pos_to_idx = {}
    for idx, (i, j) in enumerate(green_cells):
        pos_to_idx[(i, j)] = idx

    # Initialize DSU
    dsu = DSU(len(green_cells))
    for i in range(H):
        for j in range(W):
            if grid[i][j] == '#':
                for dx, dy in dirs:
                    ni, nj = i + dx, j + dy
                    if 0 <= ni < H and 0 <= nj < W and grid[ni][nj] == '#':
                        if (ni, nj) in pos_to_idx:
                            dsu.union(pos_to_idx[(i, j)], pos_to_idx[(ni, nj)])

    # Count initial number of green components
    root_set = set()
    for idx in range(len(green_cells)):
        root = dsu.find(idx)
        root_set.add(root)
    initial_components = len(root_set)

    # Collect all red cells
    red_cells = []
    for i in range(H):
        for j in range(W):
            if grid[i][j] == '.':
                red_cells.append((i, j))

    total_red = len(red_cells)
    if total_red == 0:
        print(0)
        return

    # Precompute for each red cell, how it affects the component count
    result = 0
    for (i, j) in red_cells:
        # Create a new DSU for this scenario
        new_dsu = DSU(len(green_cells))
        for idx in range(len(green_cells)):
            for dx, dy in dirs:
                ni, nj = green_cells[idx][0] + dx, green_cells[idx][1] + dy
                if 0 <= ni < H and 0 <= nj < W and grid[ni][nj] == '#':
                    if (ni, nj) in pos_to_idx:
                        new_dsu.union(idx, pos_to_idx[(ni, nj)])
        # Now, add the new green cell (i,j)
        new_idx = len(green_cells)
        new_green_cells = green_cells + [(i, j)]
        new_pos_to_idx = {}
        for idx, (x, y) in enumerate(new_green_cells):
            new_pos_to_idx[(x, y)] = idx
        new_dsu = DSU(len(new_green_cells))
        for idx in range(len(new_green_cells)):
            for dx, dy in dirs:
                ni, nj = new_green_cells[idx][0] + dx, new_green_cells[idx][1] + dy
                if 0 <= ni < H and 0 <= nj < W and grid[ni][nj] == '#':
                    if (ni, nj) in new_pos_to_idx:
                        new_dsu.union(idx, new_pos_to_idx[(ni, nj)])
        new_components = len(set(new_dsu.find(i) for i in range(len(new_green_cells))))
        result += new_components

    # Compute expected value
    numerator = result
    denominator = total_red
    # Compute modular inverse of denominator
    inv_denominator = pow(denominator, MOD - 2, MOD)
    answer = (numerator % MOD) * inv_denominator % MOD
    print(answer)

if __name__ == "__main__":
    main()
